angular
    .module('ecw.utility.ip.ipFn', [])
    .service('utilityipFn', [ipFnUtilityService]);

function ipFnUtilityService(){

    return {
        trimInt	: trimInt,
        trimStr	: trimStr,
        trimBool: trimBool,
        isUNE	:	isUNE,
        isSuccess	:	isSuccess,
        isFail	:	isFail,
        equalsIgnoreCase	:	equalsIgnoreCase,
        getRandomAlpha	:	getRandomAlpha,
        getRandomAplhaNum	:	getRandomAplhaNum,
        /* *** Added By _niteen.dhule *** */
        getCurrentUTCDate : getCurrentUTCDate,
        getCurrentLocalDate : getCurrentLocalDate,
        toUTC : toUTC,
        toLocale : toLocale,
    };

    function trimInt(val){
        var retValue = 0;
        try{
            retValue = (angular.isUndefined(val) || val === null || val === '' || val === 'null')? 0 : parseInt(val)
        }catch(e){ retValue = 0; }
        return retValue;
    }
    function trimStr(val){
        return (angular.isUndefined(val) || val === null || val === '' || val === 'null')? '' : val.trim();
    }
    function trimBool(val){
        var retValue = false;
        try{
            if(angular.isUndefined(val) || val === null || val === '' || val === 'null' || val == false || val == 0){
                retValue = false;
            }else if(val == true || val == 1){
                retValue = true;
            }else{
                retValue = val.trim().toUpperCase() == "TRUE"
            }
        }catch(e){}
        return retValue;
    }
    /* is Undefined, Null or Empty */
    function isUNE(val){
        var retValue = false;
        try{ retValue = (angular.isUndefined(val) || val === null || val === 'null' || val === '' || val.trim().length == 0)? true : false; } catch(e){ retValue = false; }
        return retValue;
    }
    function isSuccess(json){
        var status = 'success';
        try{
            status = json['status'];
        }catch(e){
            status=''
        }
        return 'success' === status.toLowerCase();
    }
    function isFail(json){
        var status = 'fail';
        try{
            status = json['status'];
        }catch(e){
            status=''
        }
        return 'fail' === status.toLowerCase();
    }
    function equalsIgnoreCase(str1, str2){
        if(str1 == str2)
            return true;
        else if(str1 == null || str2 == null)
            return false;
        else
            return str1.toUpperCase() === str2.toUpperCase();
    }
    function getRandomAlpha(len){
        /*Below character of String has been used to generate a random number and not a cryptography key, hense marked as NOSONAR*/
        var allowedAlpha = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ';  // NOSONAR
        var randString = '';
        if(!len){
            len = 10;
        }
        for (var i = len; i > 0; --i)
            randString += allowedAlpha[Math.round(Math.random() * (allowedAlpha.length - 1))];
        return randString;
    }
    function getRandomAplhaNum(len){
        /*Below character of String has been used to generate a random number and not a cryptography key, hense marked as NOSONAR*/
        var allowedAlphaNum = '0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ';  // NOSONAR
        var randString = '';
        if(!len){
            len = 10;
        }
        for (var i = len; i > 0; --i)
            randString += allowedAlphaNum[Math.round(Math.random() * (allowedAlphaNum.length - 1))];
        return randString;
    }

    function getCurrentUTCDate(dateFormat){
        return moment.utc().format(dateFormat);
    }

    function getCurrentLocalDate(dateFormat){
        return moment().format(dateFormat);
    }

    function toUTC(date,dateFormat){
        return moment(date).utc().format(dateFormat);
    }

    function toLocale(date,dateFormat){
        return moment(moment.utc(date).toDate()).format(dateFormat);
    }

}
