angular.module('patientQuickEnrollmentDirective', []).directive('phmPatientQuickEnrollment',
    function($http, $modal, $ocLazyLoad) {
        return {
            restrict : 'AE',
            replace : 'true',
            scope : {
                patientId : '=',
                callbackFunction: '&'
            },
            link : function(scope, element, attrs, ngModelCtrl) {
                element.click(function(){
                    $ocLazyLoad.load({
                        name: 'phmPatientQuickEnrollment',
                        files: [
                            '/mobiledoc/jsp/webemr/populationhealth/quickenrollment/js/phmPatientQuickEnrollmentModalCtrl.js',
                            '/mobiledoc/jsp/webemr/populationhealth/css/quick-enrollment-request.css',
                            '/mobiledoc/jsp/webemr/populationhealth/js/phmInterfaceService.js',
                            '/mobiledoc/jsp/webemr/behavioralhealth/directives/notesDirective/js/notesDirective.js',
                            '/mobiledoc/jsp/webemr/templates/spellCheck-tpl.js',
                            '/mobiledoc/jsp/webemr/ecwspeech/js/evaspeech.js',
                            '/mobiledoc/jsp/webemr/behavioralhealth/directives/notesDirective/css/notesDirective.css'
                        ]
                    }).then(function() {
                        $('.action-hub-modal').remove();
                        scope.phmPatientQuickEnrollmentData = {
                            patientId : scope.patientId,
                            callbackFunction: scope.callbackFunction
                        };

                        scope.openQuickEnrollmentModal=function(){
                            $modal.open({
                                templateUrl: makeURL('/mobiledoc/jsp/webemr/populationhealth/quickenrollment/view/patient-quick-enrollment-modal.html?'),
                                controller: 'patientQuickEnrollmentModalCtrl',
                                controllerAs: 'patientQuickEnrollmentCtrl',
                                backdrop: 'static',
                                windowClass: 'quick-enroll custom-modal quick-enroll-w420',
                                animation: true,
                                resolve: {
                                    phmPatientQuickEnrollmentData: function () {
                                        return scope.phmPatientQuickEnrollmentData;
                                    }
                                }
                            });
                        }
                        scope.openQuickEnrollmentModal();
                        }, function(e) {
                    });
                });
            }
        };
    });
